class ASTNode:
    type: str
    value: float
    op: str
    left: "ASTNode"
    right: "ASTNode"
    operand: "ASTNode"

    def __init__(self, node_type: str, **kwargs):
        self.type = node_type
        for key, value in kwargs.items():
            setattr(self, key, value)

    def __repr__(self) -> str:
        if self.type == "number":
            return f"Number({self.value})"
        elif self.type == "binop":
            return f"BinaryOp({self.op}, {self.left}, {self.right})"
        elif self.type == "unary":
            return f"UnaryOp({self.op}, {self.operand})"
        return f"ASTNode({self.type})"


def parse(expression: str) -> ASTNode:
    if not expression.strip():
        raise ValueError("Empty expression")

    tokens = []
    i = 0
    n = len(expression)

    while i < n:
        c = expression[i]

        if c == " ":
            i += 1
            continue

        if c in "()+-*/":
            tokens.append(c)
            i += 1
        elif c.isdigit() or c == ".":
            num_str = ""
            while i < n and (expression[i].isdigit() or expression[i] == "."):
                num_str += expression[i]
                i += 1
            try:
                num = float(num_str)
                tokens.append(("number", num))
            except ValueError:
                raise ValueError(f"Invalid number format: {num_str}")
        else:
            raise ValueError(f"Invalid token: {c}")

    ast = parse_expression(tokens)

    # Check for remaining tokens (unmatched parentheses or operators)
    if tokens:
        raise ValueError("Unmatched parenthesis or invalid expression")

    return ast


def parse_expression(tokens):
    return parse_additive(tokens)


def parse_additive(tokens):
    left = parse_multiplicative(tokens)

    while tokens and tokens[0] in ("+", "-"):
        op = tokens.pop(0)
        right = parse_multiplicative(tokens)
        left = ASTNode("binop", op=op, left=left, right=right)

    return left


def parse_multiplicative(tokens):
    left = parse_unary(tokens)

    while tokens and tokens[0] in ("*", "/"):
        op = tokens.pop(0)
        right = parse_unary(tokens)
        left = ASTNode("binop", op=op, left=left, right=right)

    return left


def parse_unary(tokens):
    if tokens and tokens[0] == "-":
        op = tokens.pop(0)
        operand = parse_primary(tokens)
        return ASTNode("unary", op=op, operand=operand)
    else:
        return parse_primary(tokens)


def parse_primary(tokens):
    if not tokens:
        raise ValueError("Unexpected end of expression")

    token = tokens.pop(0)

    if token == "(":
        expr = parse_expression(tokens)
        if not tokens or tokens[0] != ")":
            raise ValueError("Unmatched parenthesis")
        tokens.pop(0)
        return expr
    elif token == ")":
        raise ValueError("Unmatched parenthesis")
    elif isinstance(token, tuple) and token[0] == "number":
        return ASTNode("number", value=token[1])
    else:
        raise ValueError(f"Unexpected token: {token}")


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        return node.value
    elif node.type == "binop":
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == "+":
            return left_val + right_val
        elif node.op == "-":
            return left_val - right_val
        elif node.op == "*":
            return left_val * right_val
        elif node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
    elif node.type == "unary":
        operand_val = evaluate(node.operand)
        if node.op == "-":
            return -operand_val
        else:
            raise ValueError(f"Unknown unary operator: {node.op}")

    raise ValueError(f"Unknown node type: {node.type}")
